#include <stdio.h>
int main() {
    int T, n;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        int A[n], B[n];
        for (int i = 0; i < n; i++) scanf("%d", &A[i]);
        for (int i = 0; i < n; i++) scanf("%d", &B[i]);
        int dp[n][4] = {0};
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < 4; j++) {
                if (i == 0) {
                    dp[i][j] = (A[i] + j) % 4 == B[i] ? j : 1e9;
                } else {
                    int min = 1e9;
                    for (int k = 0; k < 4; k++) {
                        if ((A[i] + k) % 4 == B[i]) {
                            min = min < dp[i-1][j] + k ? min : dp[i-1][j] + k;
                        }
                    }
                    dp[i][j] = min;
                }
            }
        }
        int min = 1e9;
        for (int i = 0; i < 4; i++) min = min < dp[n-1][i] ? min : dp[n-1][i];
        printf("%d\n", min);
    }
    return 0;
}

