import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] A = new int[n];
            int[] B = new int[n];
            for (int i = 0; i < n; i++) A[i] = sc.nextInt();
            for (int i = 0; i < n; i++) B[i] = sc.nextInt();
            int[][] dp = new int[n][4];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < 4; j++) {
                    if (i == 0) {
                        dp[i][j] = (A[i] + j) % 4 == B[i] ? j : 1000000000;
                    } else {
                        int min = 1000000000;
                        for (int k = 0; k < 4; k++) {
                            if ((A[i] + k) % 4 == B[i]) {
                                min = Math.min(min, dp[i-1][j] + k);
                            }
                        }
                        dp[i][j] = min;
                    }
                }
            }
            int min = 1000000000;
            for (int i = 0; i < 4; i++) min = Math.min(min, dp[n-1][i]);
            System.out.println(min);
        }
    }
}

